Here is an example of an event-driven state machine implemented in C:

```
// Define the states of the system
typedef enum {
  STATE_IDLE,
  STATE_RUNNING,
  STATE_STOPPED
} State_t;

// Define the events that can trigger state transitions
typedef enum {
  EVENT_START,
  EVENT_STOP,
  EVENT_RESET
} Event_t;

// Define the state machine struct
typedef struct {
  State_t state;
  void (*state_handler)(void);
} StateMachine_t;

// Define the state handlers
void idle_handler(void) {
  printf("The system is currently in idle state.\n");
}

void running_handler(void) {
  printf("The system is currently running.\n");
}

void stopped_handler(void) {
  printf("The system is currently stopped.\n");
}

// Define the state transition function
void transition_state(StateMachine_t *sm, Event_t event) {
  switch(sm->state) {
    case STATE_IDLE:
      if (event == EVENT_START) {
        sm->state = STATE_RUNNING;
        sm->state_handler = running_handler;
      }
      break;
    case STATE_RUNNING:
      if (event == EVENT_STOP) {
        sm->state = STATE_STOPPED;
        sm->state_handler = stopped_handler;
      }
      break;
    case STATE_STOPPED:
      if (event == EVENT_RESET) {
        sm->state = STATE_IDLE;
        sm->state_handler = idle_handler;
      }
      break;
    default:
      printf("Invalid state.\n");
      break;
  }
}

int main() {
  StateMachine_t sm = {STATE_IDLE, idle_handler};
  printf("Current state: %d\n", sm.state);

  //Trigger events and observe state changes
  transition_state(&sm, EVENT_START);
  sm.state_handler();
  printf("Current state: %d\n", sm.state);

  transition_state(&sm, EVENT_STOP);
  sm.state_handler();
  printf("Current state: %d\n", sm.state);

  transition_state(&sm, EVENT_RESET);
  sm.state_handler();
  printf("Current state: %d\n", sm.state);

  return 0;
}
```

In this example, the state machine is defined using enums and a struct. The state machine defines three possible states, and three possible events that can trigger state transitions. State handlers are also defined for each state, which will execute the appropriate behavior when the associated state is active.

The `transition_state` function takes the current state and an event, then evaluates the current state and the event to determine the next state and sets the appropriate state handler. Finally, the main function triggers events and observes the state changes that result from them.
